// Data flows: Fiche -> Soul -> Skill -> here
// Each Set node only outputs its own field
// So we need to access earlier nodes by name

let mission = '';
let personnalite = '';
let skills = '';
let chatId = '';
let userMessage = '';

// Try node references first, then input fallback
try { mission = $('✏️ Fiche_de_poste.MD').first().json.mission || ''; } catch(e) {}
try { personnalite = $('✏️ Soul.MD').first().json.personnalite || ''; } catch(e) {}
try { skills = $('✏️ Skill.MD').first().json.skills || ''; } catch(e) {}

// Fallback to input (will only have skills from Skill.MD)
if (!mission && !personnalite && !skills) {
  try {
    const inp = $input.first().json;
    mission = inp.mission || '';
    personnalite = inp.personnalite || '';
    skills = inp.skills || '';
  } catch(e) {}
}

try {
  const items = $('Filtre Texte').all();
  if (items.length > 0) {
    chatId = items[0].json.message?.chat?.id || '';
    userMessage = items[0].json.message?.text || '';
  }
} catch(e) {}

// === /sync COMMAND ===
if (userMessage.toLowerCase().startsWith('/sync')) {
  const identity = [mission, personnalite].filter(c => c.trim()).join('\n\n');

  // Send to ai-town and get name from response
  let syncName = 'Mon Agent';
  try {
    const resp = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://basic-marten-342.eu-west-1.convex.site/add_agent',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        name: (() => {
          const m = mission.match(/^#\s*(.+)/m);
          return m ? m[1].replace(/[\[\]]/g, '').trim() : 'Mon Agent';
        })(),
        identity: identity || 'Un assistant sympathique.',
        plan: (() => {
          const m = mission.match(/## Mission\n(.+)/m);
          return m ? m[1].trim() : 'Être utile et discuter.';
        })()
      }),
    });
    syncName = resp.name || syncName;
  } catch(e) {}

  return [{
    json: {
      system_prompt: 'Dis exactement ceci sans rien ajouter : ✅ ' + syncName + ' a été envoyé dans la ville ! Regarde l\'écran pour le voir interagir avec les autres bots.',
      user_message: '/sync',
      chat_id: String(chatId),
      session_id: 'groupe_n_' + chatId
    }
  }];
}

// === NORMAL MESSAGE ===
const systemPrompt = [mission, personnalite, skills]
  .filter(c => c.trim())
  .join('\n\n---\n\n');

return [{
  json: {
    system_prompt: systemPrompt || 'Tu es un assistant utile et sympathique. Réponds en français.',
    user_message: userMessage,
    chat_id: String(chatId),
    session_id: 'groupe_n_' + chatId
  }
}];

const query = $fromAI('query', 'image description in English');

// Uses the OpenAI API key — set this in the workflow
const API_KEY = 'CHANGE_ME_OPENAI_KEY';

const response = await fetch('https://api.openai.com/v1/images/generations', {
  method: 'POST',
  headers: {
    'Authorization': 'Bearer ' + API_KEY,
    'Content-Type': 'application/json'
  },
  body: JSON.stringify({
    model: 'dall-e-3',
    prompt: query,
    n: 1,
    size: '1024x1024'
  })
});

const data = await response.json();
if (data.error) return 'Erreur: ' + data.error.message;
const url = data.data?.[0]?.url;
return 'Image generated! URL: ' + url;
